import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { booksAPI, finesAPI, libraryCardsAPI, issuesAPI } from '../services/api';

// ── Reusable stat card ───────────────────────────────────────
const StatCard = ({ icon, color, value, label }) => (
  <div className="col-sm-6 col-lg-3">
    <div className="stat-card">
      <div className={`stat-icon ${color}`}><i className={`bi ${icon}`}></i></div>
      <div>
        <div className="stat-value">{value}</div>
        <div className="stat-label">{label}</div>
      </div>
    </div>
  </div>
);

// ── Quick-action button ──────────────────────────────────────
const QuickAction = ({ to, icon, label, color }) => (
  <Link to={to} className="lib-card p-3 d-flex align-items-center gap-3 text-decoration-none"
    style={{ color: 'var(--text-main)', transition: 'transform .2s' }}
    onMouseEnter={e => e.currentTarget.style.transform='translateY(-2px)'}
    onMouseLeave={e => e.currentTarget.style.transform='translateY(0)'}>
    <div className={`stat-icon ${color}`} style={{ flexShrink: 0 }}>
      <i className={`bi ${icon}`}></i>
    </div>
    <span style={{ fontWeight: 500, fontSize: '.92rem' }}>{label}</span>
    <i className="bi bi-chevron-right ms-auto text-muted" style={{ fontSize: '.75rem' }}></i>
  </Link>
);

// ──────────────────────────────────────────────────────────────
const DashboardPage = () => {
  const { currentUser } = useAuth();
  const role = currentUser?.role;

  const [loading, setLoading] = useState(true);
  const [data, setData] = useState({
    books: [],
    fines: [],
    requests: [],
    myCard: null,
    issues: []
  });

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        const booksReq = booksAPI.getAll();

        if (role === 'Student') {
          const finesReq = finesAPI.getMyFines();
          const cardReq = libraryCardsAPI.getMyCard().catch(() => ({ data: null }));
          const issuesReq = issuesAPI.getAll(); // Handled by standard get API

          const [bRes, fRes, cRes, iRes] = await Promise.all([booksReq, finesReq, cardReq, issuesReq]);
          setData({
            books: bRes.data || [],
            fines: fRes.data || [],
            myCard: cRes.data || null,
            issues: iRes.data || []
          });
        } else {
          const finesReq = finesAPI.getAll();
          const cardsReq = libraryCardsAPI.getAll();
          const issuesReq = issuesAPI.getAll();

          const [bRes, fRes, cRes, iRes] = await Promise.all([booksReq, finesReq, cardsReq, issuesReq]);
          setData({
            books: bRes.data || [],
            fines: fRes.data || [],
            requests: cRes.data || [],
            issues: iRes.data || []
          });
        }
      } catch (err) {
        console.error("Dashboard fetch error", err);
      } finally {
        setLoading(false);
      }
    };
    fetchDashboardData();
  }, [role]);

  if (loading) return <div className="text-center py-5"><div className="spinner-border text-primary text-center"></div></div>;

  const unpaidFines = data.fines.filter(f => f.status === 'Unpaid');
  const availableBooks = data.books.filter(b => b.availableCopies > 0).length;

  return (
    <div className="page-wrapper">
      <div className="container">
        {/* ── Header ─────────────────────────────────────── */}
        <div className="d-flex align-items-center gap-3 mb-4 flex-wrap">
          <div style={{ width: 54, height: 54, borderRadius: '50%', background: 'var(--primary)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <i className="bi bi-person-fill text-white" style={{ fontSize: '1.4rem' }}></i>
          </div>
          <div>
            <h2 className="section-title mb-0">Hello, {currentUser?.name?.split(' ')[0]}! 👋</h2>
            <span className={`badge-role badge-${role?.toLowerCase()}`}>{role} Dashboard</span>
          </div>
        </div>

        {/* ══════════ STUDENT DASHBOARD ══════════ */}
        {role === 'Student' && (
          <>
            {/* Stats */}
            <div className="row g-3 mb-4">
              <StatCard icon="bi-journals"          color="red"   value={availableBooks}             label="Books Available" />
              <StatCard icon="bi-credit-card"       color="gold"  value={data.myCard ? 1 : 0} label="Library Card" />
              <StatCard icon="bi-currency-rupee"    color="green" value={'₹' + unpaidFines.reduce((s,f) => s + f.fineAmount, 0)} label="Unpaid Fines" />
              <StatCard icon="bi-check-circle"      color="blue"  value={data.issues.filter(i=>!i.returnDate).length} label="Active Books Issued" />
            </div>

            {/* Quick actions */}
            <div className="mb-4">
              <h5 className="section-title mb-2" style={{ fontSize: '1.1rem' }}>Quick Actions</h5>
              <div className="row g-3">
                <div className="col-md-4"><QuickAction to="/books"        icon="bi-search"       color="red"   label="Browse Books" /></div>
                <div className="col-md-4"><QuickAction to="/request-card" icon="bi-credit-card"  color="gold"  label="View Library Card" /></div>
                <div className="col-md-4"><QuickAction to="/fines"        icon="bi-currency-rupee" color="green" label="View My Fines" /></div>
              </div>
            </div>

            {/* My Issues */}
            <div className="lib-card">
              <div className="lib-card-header">
                <h5><i className="bi bi-list-check me-2"></i>My Currently Issued Books</h5>
              </div>
              <div className="table-responsive p-0">
                <table className="lib-table">
                  <thead><tr><th>#</th><th>Book</th><th>Issue Date</th><th>Due Date</th></tr></thead>
                  <tbody>
                    {data.issues.filter(r => !r.returnDate).length === 0 ? (
                      <tr><td colSpan="4" className="text-center text-muted py-3">No active issued books. <Link to="/books">Browse books</Link></td></tr>
                    ) : (
                      data.issues.filter(r => !r.returnDate).map((r, i) => (
                        <tr key={r._id}>
                          <td>{i+1}</td>
                          <td>{r.book?.title}</td>
                          <td>{new Date(r.issueDate).toLocaleDateString()}</td>
                          <td style={{ color: 'var(--danger)' }}>{new Date(r.dueDate).toLocaleDateString()}</td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}

        {/* ══════════ LIBRARIAN DASHBOARD ══════════ */}
        {role === 'Librarian' && (
          <>
            <div className="row g-3 mb-4">
              <StatCard icon="bi-journals"       color="red"   value={data.books.length}    label="Total Books" />
              <StatCard icon="bi-clock-history"  color="gold"  value={data.requests.filter(r=>r.status==='pending').length} label="Pending Cards" />
              <StatCard icon="bi-check-circle"   color="green" value={data.requests.filter(r=>r.status==='approved').length} label="Approved Cards" />
              <StatCard icon="bi-exclamation-triangle" color="blue" value={'₹' + unpaidFines.reduce((s,f) => s + f.fineAmount, 0)} label="Unpaid Fines" />
            </div>

            <div className="row g-3 mb-4">
              <div className="col-md-6"><QuickAction to="/books" icon="bi-journals" color="red" label="Manage Book Catalog" /></div>
              <div className="col-md-6"><QuickAction to="/fines" icon="bi-currency-rupee" color="gold" label="Fine Records" /></div>
            </div>

            <div className="lib-card">
              <div className="lib-card-header">
                <h5><i className="bi bi-inbox me-2"></i>Pending Card Applications</h5>
              </div>
              <div className="table-responsive">
                <table className="lib-table">
                  <thead><tr><th>#</th><th>Student</th><th>Date</th><th>Status</th><th>Notes</th><th>Action</th></tr></thead>
                  <tbody>
                    {data.requests.filter(r => r.status === 'pending').length === 0 ? (
                      <tr><td colSpan="6" className="text-center text-muted py-3">No pending applications</td></tr>
                    ) : (
                      data.requests.filter(r => r.status === 'pending').map((r, i) => (
                        <tr key={r._id}>
                          <td>{i+1}</td><td>{r.student?.name}</td><td>{new Date(r.createdAt).toLocaleDateString()}</td>
                          <td><span className="badge-role badge-pending">Pending</span></td>
                          <td>{r.applicationNotes || 'N/A'}</td>
                          <td>
                            <button className="btn btn-sm btn-lib-primary me-1" style={{ padding: '.2rem .6rem', fontSize: '.75rem' }}>Approve</button>
                            <button className="btn btn-sm btn-lib-secondary" style={{ padding: '.2rem .6rem', fontSize: '.75rem' }}>Reject</button>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}

        {/* ══════════ ADMIN DASHBOARD ══════════ */}
        {role === 'Admin' && (
          <>
            <div className="row g-3 mb-4">
              <StatCard icon="bi-people"         color="red"   value="Admin View"                    label="System User" />
              <StatCard icon="bi-journals"       color="gold"  value={data.books.length}   label="Total Books" />
              <StatCard icon="bi-credit-card"    color="green" value={data.requests.length}      label="Total Cards" />
              <StatCard icon="bi-currency-rupee" color="blue"  value={`₹${unpaidFines.reduce((s,f)=>s+f.fineAmount,0)}`} label="Pending Fines" />
            </div>

            <div className="row g-3 mb-4">
              <div className="col-md-4"><QuickAction to="/books" icon="bi-journals"       color="red"   label="Manage Books" /></div>
              <div className="col-md-4"><QuickAction to="/fines" icon="bi-currency-rupee" color="gold"  label="Fine Management" /></div>
              <div className="col-md-4"><QuickAction to="/"      icon="bi-people"         color="green" label="User Management" /></div>
            </div>

            <div className="lib-card">
              <div className="lib-card-header"><h5><i className="bi bi-bar-chart me-2"></i>System Overview</h5></div>
              <div className="p-4">
                <div className="row g-4 text-center">
                  {[
                    { label: 'Books Available', value: availableBooks,         color: '#06d6a0' },
                    { label: 'Books Issued',    value: data.books.length - availableBooks, color: '#e94560' },
                    { label: 'Approved Cards',  value: data.requests.filter(r=>r.status==='approved').length, color: '#6366f1' },
                    { label: 'Active Fines',    value: unpaidFines.length, color: '#f0a500' },
                  ].map((item, i) => (
                    <div className="col-6 col-md-3" key={i}>
                      <div style={{ fontFamily: 'Playfair Display,serif', fontSize: '2.2rem', fontWeight: 700, color: item.color }}>{item.value}</div>
                      <div style={{ fontSize: '.78rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '.06em' }}>{item.label}</div>
                    </div>
                  ))}
                </div>

                <div className="mt-4">
                  <div className="d-flex justify-content-between mb-1" style={{ fontSize: '.82rem' }}>
                    <span>Books availability</span>
                    <span>{Math.round((availableBooks/Math.max(data.books.length,1))*100)}%</span>
                  </div>
                  <div className="progress" style={{ height: '8px', borderRadius: '4px' }}>
                    <div className="progress-bar" role="progressbar"
                      style={{ width: `${(availableBooks/Math.max(data.books.length,1))*100}%`, background: 'var(--success)', borderRadius: '4px' }}>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default DashboardPage;
